import {
	getX,
	getY
} from './default_options.js';
import { leftExtent } from './extent.js'

export default function getQuadtree(options){
	return new Quadtree(options)
}

export class Quadtree{
	constructor(options){
		if( options && ( typeof options.getX !== 'function' || typeof options.getY !== 'function' ) ){
			throw Error('四叉树配置出错: getX 或者 getY 不为函数');
		}

		this.getX = options && options.getX ? options.getX : getX;
		this.getY = options && options.getY ? options.getY : getY;

		this.root = null;
		this.x0 = undefined;
		this.x1 = undefined;
		this.y0 = undefined;
		this.y1 = undefined;
	}
	extent(x0, y0, x1, y1){
		if( x0 > this.x0 ){
			x0 = this.x0;
		}
		if( x1 < this.x1 ){
			x1 = this.x1;
		}
		if( y0 > this.y0 ){
			y0 = this.y0;
		}
		if( y1 < this.y1 ){
			y1 = this.y1;
		}

		[this.x0, this.x1] = leftExtent(x0, x1);
		[this.y0, this.y1] = leftExtent(y0, y1)

		return this;
	}
	addArray(array){
		let
			maxX = this.getX(array[0]),
			minX = this.getX(array[0]),
			maxY = this.getY(array[0]),
			minY = this.getX(array[0]);

		array.forEach((data)=>{
			let x = this.getX(data),
					y = this.getY(data);

			if( maxX < x ){
				maxX = x;
			}
			if( minX > x ){
				minX = x;
			}
			if( maxY < y ){
				maxY = y;
			}
			if( minY > y ){
				minY = y;
			}

		});

		this.extent( minX, minY, maxX, maxY );


		array.forEach((data)=>{
			this.add( data );
		})
		return this;
	}
	add(data){
		let
			parent,
			node = this.root,
			x = this.getX(data),
			y = this.getY(data),
			leaf = {
				data
			},
			x0 = this.x0,
			y0 = this.y0,
			x1 = this.x1,
			y1 = this.y1,
			xm,
			ym,
			xp,
			yp,
			right,
			bottom,
			i,
			j;

		if( !this.root ){//	四叉树为空，一个节点都没有
			this.root = leaf
			return this;
		}

		while (node.length) {//	四叉树已经有两个以上不同的节点了，计算找到离四叉树最接近的区域
			if (right = x >= (xm = (x0 + x1) / 2)){
				x0 = xm;
			}else{
				x1 = xm;
			}
			if (bottom = y >= (ym = (y0 + y1) / 2)){
				y0 = ym;
			}else{
				y1 = ym;
			}
			parent = node;
			node = node[i = bottom << 1 | right]
			if ( !node ) {// 该区域不存在节点，直接赋值
				parent[i] = leaf;
				return this;
			}
		}

		xp = this.getX(node.data);
		yp = this.getY(node.data);
		if (x === xp && y === yp){//节点重复
			return this;
		}

		do {
			if( parent ){
				parent = parent[i] = new Array(4)//表示最接近的区域的数组
			}else{
				parent = this.root = new Array(4);//只有一个节点	
			}

			if (right = x >= (xm = (x0 + x1) / 2)){
				x0 = xm;
			} else{
				x1 = xm;
			}
			if (bottom = y >= (ym = (y0 + y1) / 2)){
				y0 = ym;
			} else{
				y1 = ym;
			}

			i = bottom << 1 | right;
			j = (yp >= ym) << 1 | (xp >= xm)

		} while ( i === j );
		parent[j] = node;
		parent[i] = leaf;

		return this;
	}
	initNodeRange(node, x0, y0, x1, y1){
		node.x0 = x0;
		node.y0 = y0;
		node.x1 = x1;
		node.y1 = y1;

		return node;
	}
	initRange(){
		var quads = [], node = this.root, child, x0, y0, x1, y1;
		if (node) {
			quads.push(this.initNodeRange(node, this.x0, this.y0, this.x1, this.y1));
		}
		while (node = quads.pop()) {
			x0 = node.x0;
			y0 = node.y0;
			x1 = node.x1;
			y1 = node.y1;
			if (node.length) {
				var xm = (x0 + x1) / 2,
						ym = (y0 + y1) / 2;
				if (child = node[3]) {
					quads.push(this.initNodeRange(child, xm, ym, x1, y1));
				}
				if (child = node[2]) {
					quads.push(this.initNodeRange(child, x0, ym, xm, y1));
				}
				if (child = node[1]) {
					quads.push(this.initNodeRange(child, xm, y0, x1, ym));
				}
				if (child = node[0]) {
					quads.push(this.initNodeRange(child, x0, y0, xm, ym));
				}
			}
		}
		return this;
	}
	visit(callback){
		var quads = [], node = this.root;
		if (node) {
			quads.push(node);
		}
		while (node = quads.pop()) {
			if (!callback(node) && node.length) {
				node.forEach((item)=>{
					quads.push(item);
				});
			}
		}
		return this;
	}
	visitAfter(callback){
		let next = this.toArray(),
				node;
		while (node = next.pop()) {
			callback(node);
		}
		return this;
	}
	toArray(onlyLeaf = false){
		var quads = [], next = [], node;
		if (this.root){
			quads.push(this.root);
		}
		while (node = quads.pop()) {
			if (node.length) {
				node.forEach((item)=>{
					quads.push(item);
				});
				if( onlyLeaf ){
					continue ;
				}
			}
			next.push(node);
		}
		return next;
	}
	remove(d){
		var parent,
				node = this.root,
				retainer,
				previous,
				next,
				x0 = this.x0,
				y0 = this.y0,
				x1 = this.x1,
				y1 = this.y1,
				x,
				y,
				xm,
				ym,
				right,
				bottom,
				i,
				j;

		// If the tree is empty, initialize the root as a leaf.
		if (!node) return this;

		// Find the leaf node for the point.
		// While descending, also retain the deepest parent with a non-removed sibling.
		if (node.length) while (true) {
			if (right = x >= (xm = (x0 + x1) / 2)) x0 = xm; else x1 = xm;
			if (bottom = y >= (ym = (y0 + y1) / 2)) y0 = ym; else y1 = ym;
			if (!(parent = node, node = node[i = bottom << 1 | right])) return this;
			if (!node.length) break;
			if (parent[(i + 1) & 3] || parent[(i + 2) & 3] || parent[(i + 3) & 3]) retainer = parent, j = i;
		}

		// Find the point to remove.
		while (node.data !== d) if (!(previous = node, node = node.next)) return this;
		if (next = node.next) delete node.next;

		// If there are multiple coincident points, remove just the point.
		if (previous) return (next ? previous.next = next : delete previous.next), this;

		// If this is the root point, remove it.
		if (!parent) return this.root = next, this;

		// Remove this leaf.
		next ? parent[i] = next : delete parent[i];

		// If the parent now contains exactly one leaf, collapse superfluous parents.
		if ((node = parent[0] || parent[1] || parent[2] || parent[3])
				&& node === (parent[3] || parent[2] || parent[1] || parent[0])
				&& !node.length) {
			if (retainer) retainer[j] = node;
			else this.root = node;
		}

		return this;
	}
}
