<template>
	<div
		class="container"
		ref="container"></div>
</template>

<script>
	import * as d3 from 'd3'
	import getQuadtree from './d3-quadtree/quadtree.js'

	export default {
		mounted(){
			let container = this.$refs.container,
					width = 512,
					height = 512,
					quad = getQuadtree({
						getX(data){
							return data.x;
						},
						getY(data){
							return data.y;
						}
					}).addArray(d3.range(1200).map(function() {
							return {
								x: Math.floor(Math.random() * width),
								y: Math.floor(Math.random() * height)
							}
						}))
						.initRange(),
					svg = d3.select(container)
						.append('svg')
						.attr( 'width', width )
						.attr( 'height', height )
						.style("font", "12px sans-serif"),

					brush = d3.brush()
						.on("brush", brushed);

			// quad.visit((node)=>{
			// 	console.log('node:', node);
			// });

			svg.selectAll(".node")
				.data(quad.toArray())
				.enter().append("rect")
				.attr("class", "node")
				.attr("x", function(d) { return d.x0; })
				.attr("y", function(d) { return d.y0; })
				.attr("width", function(d) { return d.y1 - d.y0; })
				.attr("height", function(d) { return d.x1 - d.x0; });

			var point = svg.selectAll(".point")
				.data(quad.toArray(true))
				.enter().append("circle")
					.attr("class", "point")
					.attr("cx", function(d) { return d.data.x; })
					.attr("cy", function(d) { return d.data.y; })
					.attr("r", 1);

			svg.append("g")
					.attr("class", "brush")
					.call(brush)
					.call(brush.move, [[100, 100], [200, 200]]);

			function brushed() {
				var extent = d3.brushSelection(this);
				point.each(function(d) { d.scanned = d.selected = false; });
				search(quad, extent[0][0], extent[0][1], extent[1][0], extent[1][1]);
				point.classed("point--scanned", function(d) { return d.scanned; });
				point.classed("point--selected", function(d) { return d.selected; });
			}

			function search(quadtree, x0, y0, x3, y3) {
				quadtree.visit(function(d) {
					let x1 = d.x0,
							x2 = d.x1,
							y1 = d.y0,
							y2 = d.y1

					if (!d.length) {
						let { x, y } = d.data;
						d.scanned = true;
						d.selected = (x >= x0) && (x < x3) && (y >= y0) && (y < y3);
					}
					return (x1 >= x3 || y1 >= y3 || x2 < x0 || y2 < y0);
				});
			}
		}
	}
</script>

<style lang="less">
	.point {
		fill: #000;
		fill-opacity: 0.4;
	}
	.point--scanned {
		fill: orange;
		fill-opacity: 1;
		stroke: orange;
		stroke-width: 3px;
	}

	.point--selected {
		fill: red;
		fill-opacity: 1;
		stroke: red;
		stroke-width: 5px;
	}
	.node {
		fill: none;
		stroke: #ccc;
		shape-rendering: crispEdges;
	}
</style>